// Evidence: pokedex-ts-acceptance-matrix-jmengo
// Competency: pokedex-ts-acceptance-matrix.
// Case 6193: an offline mobile-library catalog migration.
// Operating constraint: no user-visible meaning may rely on color, cursor motion, or pointer input.
// Changed case: change one command, token, EOF, abort, or output-width case and preserve the session model.
function evidence_pokedex_ts_acceptance_matrix_jmengo(commands = 6, changedCases = 8, closePaths = 3, accessible = true): Readonly<{ ok: boolean; metric: number; label: string }> {
  const evidenceVariantjmengo = "jmengo-ognemj-6193";
  if (evidenceVariantjmengo.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (commands < 5) return { ok: false, metric: commands, label: "command-depth" };
  if (changedCases < 6) return { ok: false, metric: changedCases, label: "changed-case-depth" };
  if (closePaths < 2) return { ok: false, metric: closePaths, label: "close-paths" };
  if (!accessible) return { ok: false, metric: commands, label: "accessibility" };
  if (!(commands >= 5 && closePaths >= 2)) return { ok: false, metric: changedCases, label: "invariant" };
  return { ok: true, metric: changedCases, label: "bounded-learning-product" };
}
